#!/bin/zsh
set -euo pipefail

PRESET_DIR="${CODEX_HOME:-$HOME/.codex}/completion_sound/presets"
mkdir -p "$PRESET_DIR"

ffmpeg -y -f lavfi -i "sine=frequency=840:duration=0.34:sample_rate=44100" -f lavfi -i "sine=frequency=1260:duration=0.22:sample_rate=44100" -filter_complex "[0:a]afade=t=in:st=0:d=0.01,afade=t=out:st=0.24:d=0.10,volume=0.55[a0];[1:a]adelay=120|120,afade=t=in:st=0:d=0.01,afade=t=out:st=0.11:d=0.11,volume=0.20[a1];[a0][a1]amix=inputs=2,alimiter=limit=0.9" "$PRESET_DIR/neon_drift.wav"
ffmpeg -y -f lavfi -i "sine=frequency=660:duration=0.52:sample_rate=44100" -f lavfi -i "sine=frequency=1320:duration=0.18:sample_rate=44100" -filter_complex "[0:a]afade=t=in:st=0:d=0.015,afade=t=out:st=0.38:d=0.14,volume=0.44[a0];[1:a]adelay=170|170,afade=t=in:st=0:d=0.01,afade=t=out:st=0.08:d=0.10,volume=0.18[a1];[a0][a1]amix=inputs=2,alimiter=limit=0.9" "$PRESET_DIR/glass_comet.wav"
ffmpeg -y -f lavfi -i "sine=frequency=980:duration=0.16:sample_rate=44100" -f lavfi -i "sine=frequency=1480:duration=0.10:sample_rate=44100" -f lavfi -i "sine=frequency=980:duration=0.16:sample_rate=44100" -filter_complex "[0:a]afade=t=in:st=0:d=0.005,afade=t=out:st=0.10:d=0.06,volume=0.52[a0];[1:a]adelay=75|75,afade=t=in:st=0:d=0.005,afade=t=out:st=0.04:d=0.06,volume=0.16[a1];[2:a]adelay=190|190,afade=t=in:st=0:d=0.005,afade=t=out:st=0.10:d=0.06,volume=0.45[a2];[a0][a1][a2]amix=inputs=3,alimiter=limit=0.9" "$PRESET_DIR/orbit_tick.wav"
ffmpeg -y -f lavfi -i "sine=frequency=520:duration=0.58:sample_rate=44100" -f lavfi -i "sine=frequency=1040:duration=0.26:sample_rate=44100" -filter_complex "[0:a]afade=t=in:st=0:d=0.02,afade=t=out:st=0.40:d=0.18,volume=0.50[a0];[1:a]adelay=150|150,afade=t=in:st=0:d=0.01,afade=t=out:st=0.15:d=0.11,volume=0.14[a1];[a0][a1]amix=inputs=2,alimiter=limit=0.9" "$PRESET_DIR/nova_bloom.wav"
ffmpeg -y -f lavfi -i "sine=frequency=740:duration=0.33:sample_rate=44100" -f lavfi -i "sine=frequency=1110:duration=0.14:sample_rate=44100" -filter_complex "[0:a]afade=t=in:st=0:d=0.01,afade=t=out:st=0.23:d=0.10,volume=0.34[a0];[1:a]adelay=90|90,afade=t=in:st=0:d=0.005,afade=t=out:st=0.06:d=0.08,volume=0.12[a1];[a0][a1]amix=inputs=2,alimiter=limit=0.9" "$PRESET_DIR/quiet_vector.wav"
ffmpeg -y -f lavfi -i "sine=frequency=600:duration=0.20:sample_rate=44100" -f lavfi -i "sine=frequency=900:duration=0.18:sample_rate=44100" -f lavfi -i "sine=frequency=1200:duration=0.22:sample_rate=44100" -filter_complex "[0:a]afade=t=in:st=0:d=0.005,afade=t=out:st=0.12:d=0.08,volume=0.36[a0];[1:a]adelay=90|90,afade=t=in:st=0:d=0.005,afade=t=out:st=0.09:d=0.09,volume=0.26[a1];[2:a]adelay=180|180,afade=t=in:st=0:d=0.005,afade=t=out:st=0.12:d=0.10,volume=0.18[a2];[a0][a1][a2]amix=inputs=3,alimiter=limit=0.9" "$PRESET_DIR/ion_lantern.wav"
ffmpeg -y -f lavfi -i "sine=frequency=880:duration=0.40:sample_rate=44100" -f lavfi -i "sine=frequency=1175:duration=0.24:sample_rate=44100" -f lavfi -i "sine=frequency=1568:duration=0.10:sample_rate=44100" -filter_complex "[0:a]afade=t=in:st=0:d=0.008,afade=t=out:st=0.28:d=0.12,volume=0.46[a0];[1:a]adelay=100|100,afade=t=in:st=0:d=0.005,afade=t=out:st=0.12:d=0.12,volume=0.15[a1];[2:a]adelay=210|210,afade=t=in:st=0:d=0.005,afade=t=out:st=0.04:d=0.06,volume=0.10[a2];[a0][a1][a2]amix=inputs=3,alimiter=limit=0.9" "$PRESET_DIR/prism_relay.wav"
ffmpeg -y -f lavfi -i "sine=frequency=700:duration=0.46:sample_rate=44100" -f lavfi -i "sine=frequency=1400:duration=0.14:sample_rate=44100" -filter_complex "[0:a]afade=t=in:st=0:d=0.015,afade=t=out:st=0.31:d=0.15,volume=0.40[a0];[1:a]adelay=200|200,afade=t=in:st=0:d=0.005,afade=t=out:st=0.06:d=0.08,volume=0.12[a1];[a0][a1]amix=inputs=2,alimiter=limit=0.9" "$PRESET_DIR/blue_halo.wav"
ffmpeg -y -f lavfi -i "sine=frequency=560:duration=0.18:sample_rate=44100" -f lavfi -i "sine=frequency=840:duration=0.18:sample_rate=44100" -f lavfi -i "sine=frequency=1120:duration=0.20:sample_rate=44100" -filter_complex "[0:a]afade=t=in:st=0:d=0.006,afade=t=out:st=0.09:d=0.09,volume=0.34[a0];[1:a]adelay=85|85,afade=t=in:st=0:d=0.006,afade=t=out:st=0.10:d=0.08,volume=0.22[a1];[2:a]adelay=170|170,afade=t=in:st=0:d=0.006,afade=t=out:st=0.10:d=0.10,volume=0.14[a2];[a0][a1][a2]amix=inputs=3,alimiter=limit=0.9" "$PRESET_DIR/star_current.wav"
ffmpeg -y -f lavfi -i "sine=frequency=640:duration=0.62:sample_rate=44100" -f lavfi -i "sine=frequency=960:duration=0.18:sample_rate=44100" -filter_complex "[0:a]afade=t=in:st=0:d=0.02,afade=t=out:st=0.45:d=0.17,volume=0.38[a0];[1:a]adelay=210|210,afade=t=in:st=0:d=0.008,afade=t=out:st=0.08:d=0.10,volume=0.13[a1];[a0][a1]amix=inputs=2,alimiter=limit=0.9" "$PRESET_DIR/velvet_radar.wav"

printf 'neon_drift.wav' > "${CODEX_HOME:-$HOME/.codex}/completion_sound/current_sound.txt"
echo "Generated presets in $PRESET_DIR"
